const { tool_name, params } = $input.item.json;

const toolRegistry = {
  'github_activity_summary': { webhook: 'http://localhost:5678/webhook/github-activity', field: 'repo' },
  'send_notification': { webhook: 'http://localhost:5678/webhook/notify', field: 'channel' },
  'search_knowledge_base': { webhook: 'http://localhost:5678/webhook/rag-search', field: 'query' },
  'run_data_pipeline': { webhook: 'http://localhost:5678/webhook/data-pipeline', field: 'pipeline_id' },
  'get_system_health': { webhook: 'http://localhost:5678/webhook/health-check', field: null },
};

const tool = toolRegistry[tool_name];
if (!tool) {
  return [{ json: { error: `Unknown tool: ${tool_name}`, available: Object.keys(toolRegistry) } }];
}

const payload = tool.field && params[tool.field] ? { [tool.field]: params[tool.field], ...params } : params;

return [{ json: { tool_name, payload, webhook_url: tool.webhook } }];

const result = $input.item.json;
return [{
  json: {
    status: 'ok',
    tool: result.tool_name,
    result: result.data || result,
    used_mcp: true,
    timestamp: new Date().toISOString()
  }
}];
